// bool @OutputAscii(ptr cookie, ptr str, i64 len)
bool _FortranAioOutputAscii(void *c, const char *str, size_t len) {
  if (str && len > 0) fprintf(stderr, "%.*s", (int)len, str);
  return true;
}
// bool @OutputInteger32(ptr, i32)
bool _FortranAioOutputInteger32(void *c, int32_t val) {
  fprintf(stderr, " %d", val); return true;
}
// bool @OutputInteger64(ptr, i64)
bool _FortranAioOutputInteger64(void *c, int64_t val) {
  fprintf(stderr, " %lld", (long long)val); return true;
}
// bool @OutputReal32(ptr, float)
bool _FortranAioOutputReal32(void *c, float val) {
  fprintf(stderr, " %g", val); return true;
}
