// =====================================================
// Character
// =====================================================
// i32 @CharacterCompareScalar1(ptr, ptr, i64, i64)
int _FortranACharacterCompareScalar1(const char *a, const char *b,
    size_t a_len, size_t b_len) {
  size_t min_len = a_len < b_len ? a_len : b_len;
  for (size_t i = 0; i < min_len; i++) {
    if (a[i] != b[i]) return a[i] < b[i] ? -1 : 1;
  }
  if (a_len < b_len) {
    for (size_t i = a_len; i < b_len; i++)
      if (' ' != b[i]) return ' ' < b[i] ? -1 : 1;
  } else if (b_len < a_len) {
    for (size_t i = b_len; i < a_len; i++)
      if (a[i] != ' ') return a[i] < ' ' ? -1 : 1;
  }
  return 0;
}
