// =====================================================
// Numeric intrinsics
// =====================================================
// i32 @Exponent8_4(double)
int _FortranAExponent8_4(double x) {
  if (x == 0.0) return 0;
  int exp;
  frexp(x, &exp);
  return exp;
}
// double @Fraction8(double)
double _FortranAFraction8(double x) {
  if (x == 0.0) return 0.0;
  int exp;
  return frexp(x, &exp) * 2.0;
}

